import { useState, useEffect, useRef } from 'react';

export function useWebSocket(url: string) {
    const [data, setData] = useState<any>(null);
    const [isConnected, setIsConnected] = useState(false);

    const generateThoughts = (status: string, name: string) => {
        if (status === 'IDLE') return [{ time: Date.now(), text: 'AWAITING INSTRUCTION...' }];
        if (status === 'ERR_NODE') return [{ time: Date.now(), text: 'CRITICAL: ANOMALY DETECTED IN MEMORY ALLOCATION' }, { time: Date.now() - 1000, text: 'ATTEMPTING RECOVERY PROTOCOL...' }];
        return [
            { time: Date.now(), text: `ANALYZING QUERY COMPLEXITY FOR ${name}` },
            { time: Date.now() - 500, text: 'ROUTING TO VECTOR DATABASE' },
            { time: Date.now() - 1200, text: 'CALCULATING OPTIMAL PATHWAY' }
        ];
    };

    const stateRef = useRef({
        queries: [
            { "time": "0s", "gpt4": 85, "sonnet": 60, "phi3_local": 30 },
            { "time": "1s", "gpt4": 88, "sonnet": 62, "phi3_local": 35 },
            { "time": "2s", "gpt4": 82, "sonnet": 58, "phi3_local": 28 },
            { "time": "3s", "gpt4": 90, "sonnet": 65, "phi3_local": 40 },
            { "time": "4s", "gpt4": 87, "sonnet": 61, "phi3_local": 32 },
            { "time": "5s", "gpt4": 92, "sonnet": 68, "phi3_local": 45 },
        ],
        tick: 5,
        agents: [
            { id: '1', name: 'AGENT_01', status: 'IDLE', task: 'AWAITING_ORCHESTRATION', uptime: '12h 45m', latency: '4ms', thoughts: [{ time: Date.now(), text: 'AWAITING INSTRUCTION...' }] },
            { id: '2', name: 'AGENT_02', status: 'EXEC', task: 'OPTIMIZING_DB_QUERY', uptime: '02h 12m', latency: '12ms', thoughts: [{ time: Date.now(), text: 'ANALYZING QUERY COMPLEXITY' }, { time: Date.now() - 500, text: 'ROUTING TO VECTOR DATABASE' }] },
            { id: '3', name: 'AGENT_03', status: 'ERR_NODE', task: 'SYS_RECOVERY', uptime: '45h 11m', latency: 'ERR', thoughts: [{ time: Date.now(), text: 'CRITICAL: ANOMALY DETECTED' }] },
            { id: '4', name: 'AGENT_04', status: 'IDLE', task: 'AWAITING_ORCHESTRATION', uptime: '11h 05m', latency: '3ms', thoughts: [{ time: Date.now(), text: 'AWAITING INSTRUCTION...' }] },
            { id: '5', name: 'AGENT_05', status: 'IDLE', task: 'AWAITING_ORCHESTRATION', uptime: '01h 55m', latency: '5ms', thoughts: [{ time: Date.now(), text: 'AWAITING INSTRUCTION...' }] },
        ],
        alerts: [
            { id: '1', msg: 'ROUTING OPTIMIZED [NODE_ALPHA]', type: 'info' },
            { id: '2', msg: 'ANOMALY DETECTED IN NODE_04', type: 'error' },
            { id: '3', msg: 'TELEMETRY SYNC COMPLETE', type: 'info' },
            { id: '4', msg: 'SYSTEM_READY [STABLE]', type: 'info' },
        ]
    });

    useEffect(() => {
        setIsConnected(true);
        let interval: any;

        const fetchData = async () => {
            try {
                const response = await fetch('/demo_data.json');
                const baseJson = await response.json();

                // Advance Chart Data
                stateRef.current.tick += 1;
                const newTime = `${stateRef.current.tick}s`;

                // Generate a new point roughly following previous trends
                const lastPoint = stateRef.current.queries[stateRef.current.queries.length - 1];
                const newPoint = {
                    time: newTime,
                    gpt4: Math.min(100, Math.max(70, lastPoint.gpt4 + (Math.random() * 10 - 5))),
                    sonnet: Math.min(80, Math.max(40, lastPoint.sonnet + (Math.random() * 10 - 5))),
                    phi3_local: Math.min(60, Math.max(20, lastPoint.phi3_local + (Math.random() * 10 - 5)))
                };

                // Shift array
                const nextQueries = [...stateRef.current.queries.slice(1), newPoint];
                stateRef.current.queries = nextQueries;

                // Simulate Agent State Changes Randomly
                let newAgents = [...stateRef.current.agents];
                if (Math.random() > 0.6) {
                    const idx = Math.floor(Math.random() * newAgents.length);
                    const states: ('IDLE' | 'EXEC' | 'ERR_NODE')[] = ['IDLE', 'EXEC', 'ERR_NODE', 'IDLE', 'EXEC'];
                    const newStatus = states[Math.floor(Math.random() * states.length)];
                    newAgents[idx] = {
                        ...newAgents[idx],
                        status: newStatus,
                        task: newStatus === 'IDLE' ? 'AWAITING_ORCHESTRATION' : newStatus === 'ERR_NODE' ? 'SYS_RECOVERY' : 'PROCESSING_TELEMETRY',
                        latency: newStatus === 'ERR_NODE' ? 'ERR' : `${Math.floor(Math.random() * 20 + 2)}ms`,
                        thoughts: generateThoughts(newStatus, newAgents[idx].name)
                    };
                } else {
                    // Just tick the active agents' thoughts
                    newAgents = newAgents.map(a => {
                        if (a.status === 'EXEC') {
                            const possibleThoughts = [
                                'RECALIBRATING WEIGHTS',
                                'QUERYING VECTOR STORE [INDEX_04]',
                                'OPTIMIZING LATENCY PATHWAY',
                                'EVALUATING LLM RESPONSE CONFIDENCE',
                                `UPDATING INTERNAL STATE [TICK_${stateRef.current.tick}]`
                            ];
                            if (Math.random() > 0.5) {
                                return {
                                    ...a,
                                    thoughts: [{ time: Date.now(), text: possibleThoughts[Math.floor(Math.random() * possibleThoughts.length)] }, ...a.thoughts].slice(0, 15)
                                };
                            }
                        }
                        return a;
                    });
                }
                stateRef.current.agents = newAgents;

                // Simulate new alerts
                if (Math.random() > 0.8) {
                    const events = ['RECALIBRATING PARAMS', 'LATENCY SPIKE DETECTED', 'NODE_02 OFFLINE', 'ROUTING OPTIMIZED'];
                    const types = ['info', 'warning', 'error', 'info'];
                    const rId = Math.floor(Math.random() * events.length);
                    const newAlert = { id: Date.now().toString(), msg: events[rId], type: types[rId] };
                    stateRef.current.alerts = [...stateRef.current.alerts.slice(1), newAlert];
                }

                const liveData = {
                    ...baseJson,
                    current_metrics: {
                        active_agents: stateRef.current.agents.filter(a => a.status === 'EXEC').length || 1,
                        db_load: 40 + Math.floor(Math.random() * 30), // Load jumps
                        cost_savings_usd: 12450 + (stateRef.current.tick * 3) + Math.floor(Math.random() * 10)
                    },
                    historical_queries: nextQueries,
                    agents: stateRef.current.agents,
                    alerts: stateRef.current.alerts,
                    rawTick: stateRef.current.tick
                };
                setData(liveData);
            } catch (e) {
                console.error("Failed fetching mock stream", e);
            }
        };

        fetchData();
        interval = setInterval(fetchData, 1000); // 1-second pulse for real-time feel

        return () => {
            clearInterval(interval);
            setIsConnected(false);
        };
    }, [url]);

    return { data, isConnected };
}
